import type { CashVoucherKind } from '../../../../../components/kt/CashVoucherList';

export interface PostingReasonAccountSource {
  debitAccountCode: string;
  creditAccountCode: string;
  erpDebitAccountCode?: string | null;
  erpCreditAccountCode?: string | null;
}

/** Auto-fill TK tiền header + TK đối ứng dòng from posting reason rule (Step 2pi / GAP-P2-PI-06). */
export function resolvePostingReasonAccounts(
  kind: CashVoucherKind,
  rule: PostingReasonAccountSource,
): { cashAccountCode: string; counterAccountCode: string } {
  const debit = (rule.erpDebitAccountCode || rule.debitAccountCode || '').trim();
  const credit = (rule.erpCreditAccountCode || rule.creditAccountCode || '').trim();
  if (kind === 'receipt') {
    return { cashAccountCode: debit, counterAccountCode: credit };
  }
  return { cashAccountCode: credit, counterAccountCode: debit };
}
